class EdgeEndpoint:
    def __init__(self, table_name, field_name, table_type, field_type):
        self.table_name = table_name
        self.field_name = field_name
        self.table_type = table_type
        self.field_type = field_type


def save_edge(endpoint):
    return [endpoint.table_name, endpoint.field_name, endpoint.table_type, endpoint.field_type]

class ContactInfo:
    def __init__(self, first_name, last_name, email, phone):
        self.first_name = first_name
        self.last_name = last_name
        self.email = email
        self.phone = phone


def create_profile(contact):
    return {'first': contact.first_name, 'last': contact.last_name, 'email': contact.email, 'phone': contact.phone}

class AddressInfo:
    def __init__(self, name, street, city, postal_code):
        self.name = name
        self.street = street
        self.city = city
        self.postal_code = postal_code


def print_address(address):
    return f'{address.name}, {address.street}, {address.city}, {address.postal_code}'

class VehicleInfo:
    def __init__(self, make, model, year, vin):
        self.make = make
        self.model = model
        self.year = year
        self.vin = vin


def register_vehicle(vehicle):
    return f'{vehicle.make}-{vehicle.model}-{vehicle.year}-{vehicle.vin}'

class MailingAddress:
    def __init__(self, street, city, state, zip_code):
        self.street = street
        self.city = city
        self.state = state
        self.zip_code = zip_code


def update_contact(address):
    return f'{address.street}|{address.city}|{address.state}|{address.zip_code}'
